/**
 * Static trivia question bank — the source of truth for gameplay content.
 * Seeded into the database (see seed.ts); the apps retrieve questions from the DB
 * at runtime. No AI / no API key is involved in serving these.
 *
 * Shape per question (kept compact):
 *   ar  — Arabic prompt
 *   en  — English prompt (short)
 *   o   — answer options in Arabic (2–6). The app is Arabic-first; English option
 *         text is optional and omitted here.
 *   c   — index of the correct option in `o`
 *   d   — difficulty (default MEDIUM)
 *
 * Keyed by category slug (must match prisma/taxonomy.ts). Expand freely — the game
 * caps its rounds at however many questions a category has.
 */
export type Difficulty = 'EASY' | 'MEDIUM' | 'HARD' | 'EXPERT';

export interface BankQuestion {
  ar: string;
  en: string;
  o: string[];
  c: number;
  d?: Difficulty;
}

